#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while(T--) {
        unsigned long long N;
        scanf("%llu", &N);
        if(N > 0 && ((N & (N+1)) == 0) && (N != 1)) {
            unsigned long long M = (N-1)/2;
            printf("%llu\n", M);
        } else {
            printf("-1\n");
        }
    }
    return 0;
}

